INSERT INTO public.sample_essays VALUES ('923da00f-16a6-4b8e-a240-43b6ceddb452', '[FORECAST WRITING] FREE Dự Đoán IELTS WRITING TUẦN (18/5-25/5)', 'forecast-writing-free-du-doan-ielts-writing-tuan-185-255', '<h1 dir="ltr"><strong>Dự đoán IELTS Writing Task 1-2 tháng 5 (18/5 - 25/5)</strong></h1>
