INSERT INTO public.sample_essays VALUES ('170447b8-e441-44db-8d9f-0eea8cc6e94d', '[FORECAST SPEAKING] Dự Đoán IELTS SPEAKING TUẦN (1/6-8/6)', 'forecast-speaking-du-doan-ielts-speaking-tuan-16-86', '<h1 dir="ltr" style="padding-left: 40px;">FORECAST SPEAKING 1/6 -8/6</h1>
<p dir="ltr" style="padding-left: 40px;">Lưu ý: đây chỉ là những đề có xu hướng được hỏi nhiều trong phòng thi, sau khi ôn những đề này vẫn cần ôn các đề còn lại trong forecast</p>
